class SecureQueryBuilder:
    """
    Builds parameterized SQL queries using ONLY whitelisted table/column names.
    All user-provided VALUES go through parameter binding ($1, $2, etc. or %s).
    Table and column names are validated against the whitelist - never interpolated
    from raw user input.
    """

    def __init__(self, table: str):
        if table not in ALLOWED_SCHEMA:
            raise ValueError(f"Table '{table}' is not allowed for searching.")
        self.table = table
        self.schema = ALLOWED_SCHEMA[table]
        self.conditions: List[Tuple[str, list]] = []
        self.params: list = []
        self.sort_specs: List[SortSpec] = []
        self.limit_val: int = DEFAULT_LIMIT
        self.offset_val: int = 0
        self.select_columns: List[str] = []
        self.full_text_query: Optional[str] = None
        self._param_counter = 0

    def _next_param(self) -> str:
        """Generate next parameter placeholder."""
        self._param_counter += 1
        return f"%s"

    def _validate_column(self, column: str) -> str:
        """Validate column against whitelist and return the safe column name."""
        if column not in self.schema["columns"]:
            raise ValueError(
                f"Column '{column}' is not allowed for table '{self.table}'. "
                f"Allowed columns: {list(self.schema['columns'].keys())}"
            )
