    def _validate_operator(self, operator: str) -> str:
        """Validate operator against whitelist."""
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(
                f"Operator '{operator}' is not allowed. "
                f"Allowed operators: {list(ALLOWED_OPERATORS.keys())}"
            )
        return ALLOWED_OPERATORS[operator]

    def select(self, columns: Optional[List[str]] = None) -> "SecureQueryBuilder":
        """Set which columns to select (validated against whitelist)."""
        if columns:
            self.select_columns = [self._validate_column(c) for c in columns]
        else:
            self.select_columns = list(self.schema["columns"].keys())
        return self

    def where(self, field: str, operator: str, value: Any) -> "SecureQueryBuilder":
        """Add a WHERE condition with parameterized value."""
        safe_column = self._validate_column(field)
        sql_operator = self._validate_operator(operator)

        if operator == "is_null":
            self.conditions.append((f'"{safe_column}" IS NULL', []))
        elif operator == "is_not_null":
            self.conditions.append((f'"{safe_column}" IS NOT NULL', []))
        elif operator == "in" or operator == "not_in":
            if not isinstance(value, (list, tuple)):
                raise ValueError(f"Operator '{operator}' requires a list value.")
            if len(value) == 0:
                raise ValueError(f"Operator '{operator}' requires a non-empty list.")
            # Limit IN clause size to prevent abuse
            if len(value) > 1000:
                raise ValueError(f"IN clause limited to 1000 values.")
            placeholders = ", ".join([self._next_param() for _ in value])
            self.conditions.append(
                (f'"{safe_column}" {sql_operator} ({placeholders})', list(value))
            )
        elif operator == "between":
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list of exactly 2 values.")
            p1 = self._next_param()
            p2 = self._next_param()
            self.conditions.append(
                (f'"{safe_column}" BETWEEN {p1} AND {p2}', [value[0], value[1]])
            )
        elif operator in ("like", "ilike"):
            # Escape special LIKE characters in user input
            escaped_value = self._escape_like(str(value))
            p = self._next_param()
            self.conditions.append(
                (f'"{safe_column}" {sql_operator} {p}', [escaped_value])
            )
        else:
            p = self._next_param()
            self.conditions.append(
                (f'"{safe_column}" {sql_operator} {p}', [value])
            )
        return self

    def full_text_search(self, query: str, columns: Optional[List[str]] = None) -> "SecureQueryBuilder":
        """
        Add PostgreSQL full-text search across specified text columns.
        Uses to_tsvector and plainto_tsquery for safe full-text search.
        """
        if columns:
            search_columns = [self._validate_column(c) for c in columns]
        else:
            search_columns = self.schema.get("text_searchable", [])

        if not search_columns:
            raise ValueError(f"No text-searchable columns defined for table '{self.table}'.")

        # Build tsvector concatenation from whitelisted columns
        tsvector_parts = " || ' ' || ".join(
            [f'COALESCE("{col}", \'\')' for col in search_columns]
        )
        p = self._next_param()
        condition = f"to_tsvector('english', {tsvector_parts}) @@ plainto_tsquery('english', {p})"
        self.conditions.append((condition, [query]))
        self.full_text_query = query
        return self

    def fuzzy_search(self, field: str, value: str, threshold: float = 0.3) -> "SecureQueryBuilder":
        """
        Add trigram similarity search (requires pg_trgm extension).
        """
        safe_column = self._validate_column(field)
        p_val = self._next_param()
        p_thresh = self._next_param()
        condition = f'similarity("{safe_column}", {p_val}) > {p_thresh}'
        self.conditions.append((condition, [value, threshold]))
        return self

    def order_by(self, field: str, direction: str = "asc") -> "SecureQueryBuilder":
        """Add ORDER BY clause with validated column and direction."""
        safe_column = self._validate_column(field)
        direction = direction.lower()
        if direction not in ALLOWED_SORT_DIRECTIONS:
            raise ValueError(f"Sort direction must be 'asc' or 'desc', got '{direction}'.")
        self.sort_specs.append(SortSpec(field=safe_column, direction=direction))
        return self

    def limit(self, limit: int) -> "SecureQueryBuilder":
        """Set LIMIT with bounds checking."""
        if not isinstance(limit, int) or limit < 0:
            raise ValueError("Limit must be a non-negative integer.")
        self.limit_val = min(limit, MAX_LIMIT)
        return self

    def offset(self, offset: int) -> "SecureQueryBuilder":
        """Set OFFSET with bounds checking."""
        if not isinstance(offset, int) or offset < 0:
            raise ValueError("Offset must be a non-negative integer.")
        self.offset_val = offset
        return self

    @staticmethod
    def _escape_like(value: str) -> str:
        """Escape special characters in LIKE patterns."""
        return value.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")

    def build(self) -> Tuple[str, list]:
        """Build the final parameterized SQL query."""
        # SELECT clause
        if not self.select_columns:
            self.select_columns = list(self.schema["columns"].keys())

        columns_sql = ", ".join([f'"{c}"' for c in self.select_columns])
        query = f'SELECT {columns_sql} FROM "{self.table}"'

        # Collect all params in order
        all_params = []

        # WHERE clause
        if self.conditions:
            where_parts = []
            for condition_sql, condition_params in self.conditions:
                where_parts.append(condition_sql)
                all_params.extend(condition_params)
            query += " WHERE " + " AND ".join(where_parts)

        # ORDER BY clause
        if self.sort_specs:
            order_parts = [
                f'"{s.field}" {s.direction.upper()}' for s in self.sort_specs
            ]
            query += " ORDER BY " + ", ".join(order_parts)
        else:
            default_order = self.schema.get("default_order", "id")
            query += f' ORDER BY "{default_order}" ASC'

        # LIMIT and OFFSET
        query += f" LIMIT %s OFFSET %s"
        all_params.extend([self.limit_val, self.offset_val])

        return query, all_params

    def build_count(self) -> Tuple[str, list]:
        """Build a COUNT query for pagination."""
        query = f'SELECT COUNT(*) FROM "{self.table}"'
        all_params = []

        if self.conditions:
            where_parts = []
            for condition_sql, condition_params in self.conditions:
                where_parts.append(condition_sql)
                all_params.extend(condition_params)
            query += " WHERE " + " AND ".join(where_parts)

        return query, all_params


