# --- Helper to parse filter values ---

import json

def parse_filter_value(filter_input: FilterInput):
    """Parse filter value, handling type coercion for different operators."""
    operator = filter_input.operator
    
    if operator in ("is_null", "is_not_null"):
        return None
    
    if operator in ("in", "not_in", "between"):
        if filter_input.values:
            return filter_input.values
        elif filter_input.value:
            try:
                parsed = json.loads(filter_input.value)
                if isinstance(parsed, list):
                    return parsed
            except (json.JSONDecodeError, TypeError):
                pass
            raise ValueError(f"Operator '{operator}' requires 'values' list or JSON array in 'value'.")
        raise ValueError(f"Operator '{operator}' requires values.")
    
    return filter_input.value


# --- Query Execution ---

def execute_search(search_input: SearchInput) -> SearchResult:
    """Execute a search query securely."""
    builder = SecureQueryBuilder(search_input.table)

    # Select columns
    if search_input.select_columns:
        builder.select(search_input.select_columns)
    else:
        builder.select()

    # Apply filters
    if search_input.filters:
        for f in search_input.filters:
            value = parse_filter_value(f)
            builder.where(f.field, f.operator, value)

    # Apply full-text search
    if search_input.full_text_search:
        fts = search_input.full_text_search
        builder.full_text_search(
            query=fts.query,
            columns=fts.columns,
        )

    # Apply fuzzy searches
    if search_input.fuzzy_searches:
        for fs in search_input.fuzzy_searches:
            builder.fuzzy_search(
                field=fs.field,
                value=fs.value,
                threshold=fs.threshold or 0.3,
            )

    # Apply sorting
    if search_input.sort:
        for s in search_input.sort:
            builder.order_by(s.field, s.direction or "asc")

    # Apply pagination
    if search_input.limit is not None:
        builder.limit(search_input.limit)
    if search_input.offset is not None:
        builder.offset(search_input.offset)

    # Build queries
    query, params = builder.build()
    count_query, count_params = builder.build_count()

    conn = None
    try:
        conn = get_connection()
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            # Execute count query
            cur.execute(count_query, count_params)
            total_count = cur.fetchone()["count"]

            # Execute main query
            cur.execute(query, params)
            rows = cur.fetchall()

        # Build results
        result_rows = [SearchResultRow(data=json.dumps(dict(row), default=str)) for row in rows]

        pagination = PaginationInfo(
            total_count=total_count,
            limit=builder.limit_val,
            offset=builder.offset_val,
            has_next_page=(builder.offset_val + builder.limit_val) < total_count,
            has_previous_page=builder.offset_val > 0,
        )

        # Create debug query (replace params with placeholders for safety)
        debug_query = query.replace("%s", "?")

        return SearchResult(
            rows=result_rows,
            pagination=pagination,
            query_debug=debug_query,
        )

    except psycopg2.Error as e:
        if conn:
            conn.rollback()
        raise Exception(f"Database error: {e.pgerror or str(e)}")
    finally:
        if conn:
            release_connection(conn)


def execute_typed_search(table: str, filters=None, full_text_search=None,
                          fuzzy_searches=None, sort=None, limit=DEFAULT_LIMIT,
                          offset=0):
    """Execute search and return raw dicts for typed results."""
    builder = SecureQueryBuilder(table)
    builder.select()

    if filters:
        for f in filters:
            value = parse_filter_value(f)
            builder.where(f.field, f.operator, value)

    if full_text_search:
        builder.full_text_search(
            query=full_text_search.query,
            columns=full_text_search.columns,
        )

    if fuzzy_searches:
        for fs in fuzzy_searches:
            builder.fuzzy_search(fs.field, fs.value, fs.threshold or 0.3)

    if sort:
        for s in sort:
            builder.order_by(s.field, s.direction or "asc")

    if limit is not None:
        builder.limit(limit)
    if offset is not None:
        builder.offset(offset)

    query, params = builder.build()
    count_query, count_params = builder.build_count()

    conn = None
    try:
        conn = get_connection()
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            cur.execute(count_query, count_params)
            total_count = cur.fetchone()["count"]

            cur.execute(query, params)
            rows = [dict(row) for row in cur.fetchall()]

        pagination = PaginationInfo(
            total_count=total_count,
            limit=builder.limit_val,
            offset=builder.offset_val,
            has_next_page=(builder.offset_val + builder.limit_val) < total_count,
            has_previous_page=builder.offset_val > 0,
        )

        return rows, pagination

    except psycopg2.Error as e:
        if conn:
            conn.rollback()
        raise Exception(f"Database error: {e.pgerror or str(e)}")
    finally:
        if conn:
            release_connection(conn)


