def setup_database():
    """Initialize database with schema and sample data."""
    conn = None
    try:
        conn = get_connection()
        with conn.cursor() as cur:
            cur.execute(SETUP_SQL)
        conn.commit()
        print("Database setup completed successfully.")
    except psycopg2.Error as e:
        if conn:
            conn.rollback()
        print(f"Database setup error: {e}")
        raise
    finally:
        if conn:
            release_connection(conn)


# --- Flask Application ---

from flask import Flask, request, jsonify
from flask_cors import CORS

app = Flask(__name__)
CORS(app)


@app.route("/graphql", methods=["POST"])
def graphql_endpoint():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No JSON body provided"}), 400

    query = data.get("query", "")
    variables = data.get("variables")
    operation_name = data.get("operationName")

    result = schema.execute(
        query,
        variables=variables,
        operation_name=operation_name,
    )

    response = {}
    if result.data:
        response["data"] = result.data
    if result.errors:
        response["errors"] = [
            {"message": str(e), "locations": e.locations, "path": e.path}
            for e in result.errors
        ]

    status_code = 200 if not result.errors else 400
    return jsonify(response), status_code


@app.route("/graphql", methods=["GET"])
def graphql_playground():
    """Serve GraphiQL playground."""
    return """
    <!DOCTYPE html>
    <html>
    <head>
        <title>Search API - GraphiQL</title>
        <link href="https://unpkg.com/graphiql/graphiql.min.css" rel="stylesheet" />
    </head>
    <body style="margin: 0;">
        <div id="graphiql" style="height: 100vh;"></div>
        <script crossorigin src="https://unpkg.com/react/umd/react.production.min.js"></script>
        <script crossorigin src="https://unpkg.com/react-dom/umd/react-dom.production.min.js"></script>
        <script crossorigin src="https://unpkg.com/graphiql/graphiql.min.js"></script>
        <script>
            const fetcher = GraphiQL.createFetcher({ url: '/graphql' });
            ReactDOM.render(
                React.createElement(GraphiQL, {
                    fetcher,
                    defaultQuery: `# Search products by category
{
  searchProducts(
    filters: [
      {field: "category", operator: EQ, value: "Electronics"},
      {field: "price", operator: LTE, value: "100"}
    ],
    sort: [{field: "price", direction: ASC}],
    limit: 10
  ) {
    products {
      id
      name
      price
      category
      brand
    }
    pagination {
      totalCount
      hasNextPage
    }
  }
}`,
                }),
                document.getElementById('graphiql'),
            );
        </script>
    </body>
    </html>
    """, 200


@app.route("/setup", methods=["POST"])
def setup_endpoint():
    """Endpoint to initialize the database."""
    try:
        setup_database()
        return jsonify({"message": "Database setup completed successfully."}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    try:
        conn = get_connection()
        with conn.cursor() as cur:
            cur.execute("SELECT 1")
        release_connection(conn)
        return jsonify({"status": "healthy", "database": "connected"}), 200
    except Exception as e:
        return jsonify({"status": "unhealthy", "error": str(e)}), 503


if __name__ == "__main__":
    import sys

    if "--setup" in sys.argv:
        setup_database()
        print("Database initialized. Run without --setup to start the server.")
    else:
        print("Starting GraphQL Search API on http://localhost:5000/graphql")
        print("Visit http://localhost:5000/graphql in browser for GraphiQL playground")
        print("POST to /setup to initialize the database with sample data")
        app.run(host="0.0.0.0", port=5000, debug=True)